mapper.sql:
WHERE br.use_yn = 'Y'

    AND br.blacklist_target_id LIKE CONCAT('%', #{blacklistTargetId}, '%')


    AND (br.title LIKE CONCAT('%', #{keyword}, '%') OR br.content LIKE CONCAT('%', #{keyword}, '%'))


    AND DATE(br.create_dt) >= #{createDtFrom}


    AND DATE(br.create_dt) <= #{createDtTo}


    AND IFNULL(br.like_count, 0) >= #{minLikeCount}


    AND br.category_code = #{categoryCode}
